mapper.select:
/* findRate */

SELECT ID, INSURANCE_TYPE, RATE_TARGET, RATE, BASE_TYPE,
       EFFECTIVE_FROM, EFFECTIVE_TO, IS_ACTIVE, CREATED_AT, UPDATED_AT
FROM INSURANCE_RATE_RULES
WHERE INSURANCE_TYPE = #{insuranceType}
  AND RATE_TARGET = #{rateTarget}
  AND IS_ACTIVE = 1
  AND EFFECTIVE_FROM <= #{baseDate}
  AND (EFFECTIVE_TO IS NULL OR EFFECTIVE_TO >= #{baseDate})
ORDER BY EFFECTIVE_FROM DESC
LIMIT 1
